// ── RESOLVE BRAND FROM REQUEST ────────────────────────────
const body = $input.first().json.body || $input.first().json;
const requestedGenre = (body.genre || body.product_category || '').toLowerCase();
const requestedBrandId = body.brand_id || null;
const productName = (body.product_name || '').toLowerCase();

// Find brand by explicit ID or by genre matching
let resolvedBrandId = requestedBrandId;

if (!resolvedBrandId) {
  // Try exact genre match
  resolvedBrandId = GENRE_ROUTING[requestedGenre];

  // Try partial match if no exact match
  if (!resolvedBrandId) {
    for (const [key, brandId] of Object.entries(GENRE_ROUTING)) {
      if (requestedGenre.includes(key) || key.includes(requestedGenre) ||
          productName.includes(key)) {
        resolvedBrandId = brandId;
        break;
      }
    }
  }

  // Default to clearstack (active brand) if still not resolved
  if (!resolvedBrandId) resolvedBrandId = 'clearstack';
}

const brand = BRANDS[resolvedBrandId];

if (!brand) {
  return [{ json: {
    error: true,
    message: `Brand '${resolvedBrandId}' not found`,
    available_brands: Object.keys(BRANDS)
  }}];
}

// Check if brand is active
if (brand.status !== 'ACTIVE') {
  return [{ json: {
    error: false,
    warning: true,
    message: `Brand '${brand.brand_name}' is ${brand.status}. Routing to ClearStack Studio instead.`,
    brand: BRANDS['clearstack'],
    original_request: body,
    routed_from: resolvedBrandId,
    routed_to: 'clearstack'
  }}];
}

return [{ json: {
  error: false,
  brand: brand,
  resolved_brand_id: resolvedBrandId,
  genre_matched: requestedGenre,
  original_request: body,
  config_version: '1.0',
  resolved_at: new Date().toISOString()
}}];

// Validate the resolved brand config before returning
const result = $input.first().json;

if (result.error) {
  return [{ json: { ...result, validated: false } }];
}

const brand = result.brand;
const issues = [];
const warnings = [];

// Check store credentials
for (const [storeName, store] of Object.entries(brand.stores || {})) {
  if (store.enabled) {
    const fields = Object.entries(store);
    for (const [key, val] of fields) {
      if (typeof val === 'string' && val.startsWith('YOUR_')) {
        issues.push(`${storeName}.${key} not configured`);
      }
    }
  }
}

// Check social credentials
for (const [platformName, platform] of Object.entries(brand.social || {})) {
  if (platform.enabled) {
    const fields = Object.entries(platform);
    for (const [key, val] of fields) {
      if (typeof val === 'string' && val.startsWith('YOUR_')) {
        warnings.push(`${platformName}.${key} not configured — will skip this platform`);
      }
    }
  }
}

// Build enabled stores list (only ones with real credentials)
const enabledStores = Object.entries(brand.stores || {})
  .filter(([name, store]) => {
    if (!store.enabled) return false;
    const hasUnconfigured = Object.values(store)
      .some(v => typeof v === 'string' && v.startsWith('YOUR_'));
    return !hasUnconfigured;
  })
  .map(([name]) => name);

// Build enabled social list
const enabledSocial = Object.entries(brand.social || {})
  .filter(([name, platform]) => {
    if (!platform.enabled) return false;
    const hasUnconfigured = Object.values(platform)
      .some(v => typeof v === 'string' && v.startsWith('YOUR_'));
    return !hasUnconfigured;
  })
  .map(([name]) => name);

return [{ json: {
  ...result,
  validated: true,
  config_issues: issues,
  config_warnings: warnings,
  enabled_stores: enabledStores,
  enabled_social: enabledSocial,
  ready_to_use: issues.length === 0
}}];
